# Generated by openai (gpt-5.2)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
  agent any

  options {
    timestamps()
    disableConcurrentBuilds()
    buildDiscarder(logRotator(numToKeepStr: '30', artifactNumToKeepStr: '30'))
    timeout(time: 90, unit: 'MINUTES')
    ansiColor('xterm')
  }

  parameters {
    text(
      name: 'ARTIFACT_URLS',
      defaultValue: '',
      description: 'One URL per line. Supports http(s)://, s3://bucket/key, artifactory://repo/path (mapped via ARTIFACTORY_BASE_URL).'
    )
    choice(
      name: 'DEPLOY_STRATEGY',
      choices: ['serial', 'parallel'],
      description: 'Deploy to servers serially or in parallel.'
    )
    string(
      name: 'PROD_SERVERS',
      defaultValue: '',
      description: 'Comma/space/newline separated list of production servers (hostnames or IPs).'
    )
    string(
      name: 'SSH_USER',
      defaultValue: 'deploy',
      description: 'SSH user for production servers.'
    )
    string(
      name: 'SSH_PORT',
      defaultValue: '22',
      description: 'SSH port.'
    )
    string(
      name: 'REMOTE_DEPLOY_DIR',
      defaultValue: '/opt/app/releases',
      description: 'Remote directory where artifacts will be uploaded.'
    )
    string(
      name: 'REMOTE_CURRENT_SYMLINK',
      defaultValue: '/opt/app/current',
      description: 'Remote symlink to point to the latest deployed release.'
    )
    booleanParam(
      name: 'RUN_REMOTE_RESTART',
      defaultValue: true,
      description: 'Run restart command on remote after deployment.'
    )
    string(
      name: 'REMOTE_RESTART_CMD',
      defaultValue: 'sudo systemctl restart app',
      description: 'Remote restart command.'
    )
    booleanParam(
      name: 'VERIFY_REMOTE',
      defaultValue: true,
      description: 'Verify remote deployment by checking files exist.'
    )
    booleanParam(
      name: 'DRY_RUN',
      defaultValue: false,
      description: 'If true, downloads still occur but no remote changes are made.'
    )
    string(
      name: 'ARTIFACTORY_BASE_URL',
      defaultValue: '',
      description: 'Base URL for artifactory:// URLs, e.g. https://artifactory.example.com/artifactory'
    )
    credentials(
      name: 'ARTIFACTORY_CREDENTIALS',
      defaultValue: '',
      description: 'Optional: username/password credentials for Artifactory/HTTP basic auth.'
    )
    credentials(
      name: 'AWS_CREDENTIALS',
      defaultValue: '',
      description: 'Optional: AWS credentials for s3:// downloads (requires aws cli on agent).'
    )
    credentials(
      name: 'SSH_CREDENTIALS',
      defaultValue: '',
      description: 'SSH private key credentials for production servers.'
    )
  }

  environment {
    WORK_DIR = "${env.WORKSPACE}/_deploy_work"
    DOWNLOAD_DIR = "${env.WORKSPACE}/_deploy_work/downloads"
    MANIFEST = "${env.WORKSPACE}/_deploy_work/manifest.json"
  }

  stages {
    stage('Validate Inputs') {
      steps {
        script {
          def urls = (params.ARTIFACT_URLS ?: '')
            .split(/\r?\n/)
            .collect { it.trim() }
            .findAll { it && !it.startsWith('#') }

          if (!urls) {
            error("ARTIFACT_URLS is empty. Provide one URL per line.")
          }

          def servers = (params.PROD_SERVERS ?: '')
            .split(/[\s,]+/)
            .collect { it.trim() }
            .findAll { it }

          if (!servers) {
            error("PROD_SERVERS is empty. Provide at least one server.")
          }

          if (!params.SSH_CREDENTIALS?.trim()) {
            error("SSH_CREDENTIALS is required.")
          }

          if (urls.any { it.startsWith('artifactory://') } && !params.ARTIFACTORY_BASE_URL?.trim()) {
            error("ARTIFACTORY_BASE_URL is required when using artifactory:// URLs.")
          }

          currentBuild.description = "Artifacts: ${urls.size()} | Servers: ${servers.size()} | Strategy: ${params.DEPLOY_STRATEGY}${params.DRY_RUN ? ' | DRY_RUN' : ''}"

          env._URLS = urls.join('\n')
          env._SERVERS = servers.join('\n')
        }
      }
    }

    stage('Prepare Workspace') {
      steps {
        sh """
          set -euo pipefail
          rm -rf '${WORK_DIR}'
          mkdir -p '${DOWNLOAD_DIR}'
        """
      }
    }

    stage('Download Artifacts') {
      steps {
        script {
          def urls = env._URLS.split('\n') as List<String>

          def downloadOne = { String url ->
            def resolvedUrl = url
            if (url.startsWith('artifactory://')) {
              def path = url - 'artifactory://'
              path = path.replaceAll('^/+', '')
              resolvedUrl = "${params.ARTIFACTORY_BASE_URL.replaceAll('/+\$','')}/${path}"
            }

            def fileName = null
            if (resolvedUrl.startsWith('s3://')) {
              def key = resolvedUrl - 's3://'
              key = key.replaceAll('^/+', '')
              fileName = key.tokenize('/').last()
            } else {
              def noQuery = resolvedUrl.split('\\?')[0]
              fileName = noQuery.tokenize('/').last()
            }

            if (!fileName) {
              error("Could not determine filename for URL: ${url}")
            }

            def outPath = "${env.DOWNLOAD_DIR}/${fileName}"

            if (resolvedUrl.startsWith('s3://')) {
              if (!params.AWS_CREDENTIALS?.trim()) {
                error("AWS_CREDENTIALS is required for s3:// downloads: ${url}")
              }
              withCredentials([[$class: 'AmazonWebServicesCredentialsBinding', credentialsId: params.AWS_CREDENTIALS]]) {
                sh """
                  set -euo pipefail
                  aws --version
                  aws s3 cp '${resolvedUrl}' '${outPath}'
                """
              }
            } else if (resolvedUrl.startsWith('http://') || resolvedUrl.startsWith('https://')) {
              if (params.ARTIFACTORY_CREDENTIALS?.trim()) {
                withCredentials([usernamePassword(credentialsId: params.ARTIFACTORY_CREDENTIALS, usernameVariable: 'BASIC_USER', passwordVariable: 'BASIC_PASS')]) {
                  sh """
                    set -euo pipefail
                    curl -fL --retry 5 --retry-delay 2 --connect-timeout 20 --max-time 1800 \\
                      -u "\$BASIC_USER:\$BASIC_PASS" \\
                      -o '${outPath}' '${resolvedUrl}'
                  """
                }
              } else {
                sh """
                  set -euo pipefail
                  curl -fL --retry 5 --retry-delay 2 --connect-timeout 20 --max-time 1800 \\
                    -o '${outPath}' '${resolvedUrl}'
                """
              }
            } else {
              error("Unsupported URL scheme: ${url}")
            }

            sh """
              set -euo pipefail
              test -s '${outPath}'
            """

            def sha = sh(script: "set -euo pipefail; sha256sum '${outPath}' | awk '{print \$1}'", returnStdout: true).trim()
            def size = sh(script: "set -euo pipefail; stat -c%s '${outPath}'", returnStdout: true).trim()

            return [sourceUrl: url, resolvedUrl: resolvedUrl, fileName: fileName, localPath: outPath, sha256: sha, sizeBytes: size]
          }

          def manifest = []
          urls.each { u ->
            manifest << downloadOne(u)
          }

          writeFile file: env.MANIFEST, text: groovy.json.JsonOutput.prettyPrint(groovy.json.JsonOutput.toJson([
            createdAt: new Date().format("yyyy-MM-dd'T'HH:mm:ssXXX"),
            buildTag: env.BUILD_TAG,
            buildUrl: env.BUILD_URL,
            artifacts: manifest
          ]))

          archiveArtifacts artifacts: "_deploy_work/downloads/*,_deploy_work/manifest.json", fingerprint: true, onlyIfSuccessful: false
        }
      }
    }

    stage('Deploy to Production') {
      steps {
        script {
          def servers = env._SERVERS.split('\n') as List<String>
          def manifest = new groovy.json.JsonSlurperClassic().parseText(readFile(env.MANIFEST))
          def artifacts = manifest.artifacts as List<Map>

          def releaseId = new Date().format('yyyyMMddHHmmss') + "-${env.BUILD_NUMBER}"
          def remoteReleaseDir = "${params.REMOTE_DEPLOY_DIR.replaceAll('/+\$','')}/${releaseId}"

          def deployToServer = { String host ->
            sshagent(credentials: [params.SSH_CREDENTIALS]) {
              sh """
                set -euo pipefail
                echo "Deploying to ${host}"
                ssh -p '${params.SSH_PORT}' -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null '${params.SSH_USER}@${host}' \\
                  'set -euo pipefail; ${params.DRY_RUN ? "echo DRY_RUN: would create ${remoteReleaseDir}" : "mkdir -p '${remoteReleaseDir}'"}'
              """

              artifacts.each { a ->
                def local = a.localPath
                def remote = "${remoteReleaseDir}/${a.fileName}"

                sh """
                  set -euo pipefail
                  ${params.DRY_RUN ? "echo DRY_RUN: would upload ${local} to ${host}:${remote}" : "scp -P '${params.SSH_PORT}' -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null '${local}' '${params.SSH_USER}@${host}':'${remote}'"}
                """

                if (params.VERIFY_REMOTE && !params.DRY_RUN) {
                  sh """
                    set -euo pipefail
                    ssh -p '${params.SSH_PORT}' -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null '${params.SSH_USER}@${host}' \\
                      'set -euo pipefail; test -s '${remote}'; echo "${a.sha256}  ${remote}" | sha256sum -c -'
                  """
                }
              }

              if (!params.DRY_RUN) {
                sh """
                  set -euo pipefail
                  ssh -p '${params.SSH_PORT}' -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null '${params.SSH_USER}@${host}' \\
                    'set -euo pipefail; ln -sfn '${remoteReleaseDir}' '${params.REMOTE_CURRENT_SYMLINK}'; echo "Current -> ${remoteReleaseDir}"'
                """
              } else {
                sh """
                  set -euo pipefail
                  echo "DRY_RUN: would update symlink ${params.REMOTE_CURRENT_SYMLINK} -> ${remoteReleaseDir} on ${host}"
                """
              }

              if (params.RUN_REMOTE_RESTART) {
                if (!params.DRY_RUN) {
                  sh """
                    set -euo pipefail
                    ssh -p '${params.SSH_PORT}' -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null '${params.SSH_USER}@${host}' \\
                      'set -euo pipefail; ${params.REMOTE_RESTART_CMD}'
                  """
                } else {
                  sh """
                    set -euo pipefail
                    echo "DRY_RUN: would run restart on ${host}: ${params.REMOTE_RESTART_CMD}"
                  """
                }
              }
            }
          }

          if (params.DEPLOY_STRATEGY == 'parallel') {
            def fanout = [:]
            servers.each { s ->
              def host = s
              fanout["deploy_${host}"] = { deployToServer(host) }
            }
            parallel fanout
          } else {
            servers.each { s ->
              deployToServer(s)
            }
          }
        }
      }
    }
  }

  post {
    always {
      sh """
        set +e
        echo "Cleaning workspace temp dir"
        rm -rf '${WORK_DIR}'
      """
    }
  }
}